"import json\nimport re\n\nlog_path = r\"C:\\Users\\mdasw\\.gemini\\antigravity-ide\\brain\\a712927e-564c-4af2-9247-098a4b5e1dad\\.system_generated\\logs\\transcript.jsonl\"\nprint(f\"Reading log file: {log_path} ...\")\n\nwith open(log_path, 'r', encoding='utf-8', errors='ignore') as f:\n    for idx, line in enumerate(f):\n        try:\n            data = json.loads(line)\n            content = data.get(\"content\", \"\")\n            \n            # Look for when we write_to_file or replace_file_content or output of file views\n            # containing the definitions of the routes\n            if \"/admin/attendance\" in content and (\"def admin_attendance\" in content or \"def teacher_attendance_leaves\" in content):\n                # Search for the Python code block\n                matches = re.findall(r\"(@app\\.route\\('/admin/attendance'.*?)(?=if __name__ ==|\\Z)\", content, re.DOTALL)\n                if matches:\n                    print(f\"\\n==========================================\")\n                    print(f\"FOUND ENTIRE CODE BLOCK IN STEP {idx+1}\")\n                    print(f\"==========================================\")\n                    # Write it out to a file so we can view it\n                    out_path = r\"C:\\Users\\mdasw\\.gemini\\antigravity-ide\\brain\\c715efb6-f438-4779-bf9b-2d391b3cadbc\\scratch\\attendance_routes_recovered.txt\"\n                    with open(out_path, \"w\", encoding=\"utf-8\") as out:\n                        out.write(matches[0])\n                    print(f\"Successfully saved to: {out_path}\")\n                    print(\"==========================================\\n\")\n                    break\n        except Exception as e:\n            pass\n            \nprint(\"Extraction complete.\")\n"